solutions.javascript:
// Solution
const express = require('express');
const app = express();
app.use((req, res, next) => {
    const timestamp = new Date().getTime();
    res.status(200).send({ message: 'Hello, World!', timestamp });
});
app.listen(3000, () => {
    console.log('Server listening on port 3000');
});

